      39: static char *ipfs_gateway(void)
      40: {
      41:   char *ipfs_path_c = NULL;
      42:   char *gateway_composed_c = NULL;
      43:   FILE *gfile = NULL;
      44:   char *gateway_env = getenv("IPFS_GATEWAY");
      45: 
      46:   if(gateway_env)
      47:     return curlx_strdup(gateway_env);
      48: 
      49:   /* Try to find the gateway in the IPFS data folder. */
      50:   ipfs_path_c = curl_getenv("IPFS_PATH");
      51: 
      52:   if(!ipfs_path_c) {
      53:     char *home = getenv("HOME");
      54:     /* fallback to "~/.ipfs", as that is the default location. */
      55:     if(home && *home)
      56:       ipfs_path_c = curl_maprintf("%s/.ipfs/", home);
      57:     if(!ipfs_path_c)
      58:       goto fail;
      59:   }
      60: 
      61:   gateway_composed_c =
      62:     curl_maprintf("%s%sgateway", ipfs_path_c,
      63:                   has_trailing_slash(ipfs_path_c) ? "" : "/");
      64: 
      65:   if(!gateway_composed_c)
      66:     goto fail;
      67: 
>>    68:   gfile = curlx_fopen(gateway_composed_c, FOPEN_READTEXT);
      69:   curl_free(gateway_composed_c);
      70: 
      71:   if(gfile) {
      72:     int c;
      73:     struct dynbuf dyn;
      74:     char *gateway = NULL;
      75:     curlx_dyn_init(&dyn, MAX_GATEWAY_URL_LEN);
      76: 
      77:     /* get the first line of the gateway file, ignore the rest */
>>    78:     while((c = getc(gfile)) != EOF && c != '\n' && c != '\r') {
      79:       char c_char = (char)c;
>>    80:       if(curlx_dyn_addn(&dyn, &c_char, 1))
      81:         goto fail;
      82:     }
      83: 
      84:     if(curlx_dyn_len(&dyn))
      85:       gateway = curlx_dyn_ptr(&dyn);
      86: 
      87:     curl_free(ipfs_path_c);
      88:     curlx_fclose(gfile);
      89: 
      90:     return gateway;
      91:   }
      92: fail:
      93:   if(gfile)
      94:     curlx_fclose(gfile);
      95:   curl_free(ipfs_path_c);
      96:   return NULL;
      97: }

