     162: static CURLcode altsvc_add(struct altsvcinfo *asi, const char *line)
     163: {
     164:   /* Example line:
     165:      h2 example.com 443 h3 shiny.example.com 8443 "20191231 10:00:00" 1
     166:    */
     167:   struct Curl_str srchost;
     168:   struct Curl_str dsthost;
     169:   struct Curl_str srcalpn;
     170:   struct Curl_str dstalpn;
     171:   struct Curl_str date;
     172:   curl_off_t srcport;
     173:   curl_off_t dstport;
     174:   curl_off_t persist;
     175:   curl_off_t prio;
     176: 
     177:   if(curlx_str_word(&line, &srcalpn, MAX_ALTSVC_ALPNLEN) ||
     178:      curlx_str_singlespace(&line) ||
     179:      curlx_str_word(&line, &srchost, MAX_ALTSVC_HOSTLEN) ||
     180:      curlx_str_singlespace(&line) ||
     181:      curlx_str_number(&line, &srcport, 65535) ||
     182:      curlx_str_singlespace(&line) ||
     183:      curlx_str_word(&line, &dstalpn, MAX_ALTSVC_ALPNLEN) ||
     184:      curlx_str_singlespace(&line) ||
     185:      curlx_str_word(&line, &dsthost, MAX_ALTSVC_HOSTLEN) ||
     186:      curlx_str_singlespace(&line) ||
     187:      curlx_str_number(&line, &dstport, 65535) ||
     188:      curlx_str_singlespace(&line) ||
     189:      curlx_str_quotedword(&line, &date, MAX_ALTSVC_DATELEN) ||
     190:      curlx_str_singlespace(&line) ||
     191:      curlx_str_number(&line, &persist, 1) ||
     192:      curlx_str_singlespace(&line) ||
     193:      curlx_str_number(&line, &prio, 0) ||
     194:      curlx_str_newline(&line))
     195:     ;
     196:   else {
     197:     char dbuf[MAX_ALTSVC_DATELEN + 1];
     198:     time_t expires = 0;
     199:     time_t now = time(NULL);
     200: 
     201:     /* The date parser works on a null-terminated string. The maximum length
     202:        is upheld by curlx_str_quotedword(). */
     203:     memcpy(dbuf, curlx_str(&date), curlx_strlen(&date));
     204:     dbuf[curlx_strlen(&date)] = 0;
     205:     Curl_getdate_capped(dbuf, &expires);
     206: 
     207:     if(now < expires) {
>>   208:       struct altsvc *as = altsvc_create(&srchost, &dsthost, &srcalpn, &dstalpn,
     209:                                         (size_t)srcport, (size_t)dstport);
     210:       if(as) {
     211:         as->expires = expires;
     212:         as->persist = persist ? 1 : 0;
     213:         altsvc_append(asi, as);
     214:       }
     215:       else
     216:         return CURLE_OUT_OF_MEMORY;
     217:     }
     218:   }
     219: 
     220:   return CURLE_OK;
     221: }

