     684: CURLcode Curl_async_take_result(struct Curl_easy *data,
     685:                                 struct Curl_resolv_async *async,
     686:                                 struct Curl_dns_entry **pdns)
     687: {
     688:   struct async_thrdd_ctx *thrdd = &async->thrdd;
     689:   struct Curl_dns_entry *dns = NULL;
     690:   CURLcode result = CURLE_OK;
     691: 
     692:   DEBUGASSERT(pdns);
     693:   *pdns = NULL;
     694:   if(!async->queries_ongoing && !async->done) {
     695:     DEBUGASSERT(0);
     696:     return CURLE_FAILED_INIT;
     697:   }
     698: 
     699: #ifdef USE_HTTPSRR_ARES
     700:   /* best effort, ignore errors */
     701:   if(thrdd->rr.channel)
     702:     (void)Curl_ares_perform(thrdd->rr.channel, 0);
     703: #endif
     704: #ifndef ENABLE_WAKEUP
     705:   Curl_async_thrdd_multi_process(data->multi);
     706: #endif
     707: 
     708:   if(!async->done)
     709:     return CURLE_AGAIN;
     710: 
     711:   Curl_expire_done(data, EXPIRE_ASYNC_NAME);
     712:   if(async->result) {
     713:     result = async->result;
     714:     goto out;
     715:   }
     716: 
     717:   if((thrdd->res_A && thrdd->res_A->res) ||
     718:      (thrdd->res_AAAA && thrdd->res_AAAA->res)) {
>>   719:     dns = Curl_dnscache_mk_entry2(
     720:       data, async->dns_queries,
     721:       thrdd->res_A ? &thrdd->res_A->res : NULL,
     722:       thrdd->res_AAAA ? &thrdd->res_AAAA->res : NULL,
     723:       async->hostname, async->port);
     724:     if(!dns) {
     725:       result = CURLE_OUT_OF_MEMORY;
     726:       goto out;
     727:     }
     728: 
     729: #ifdef USE_HTTPSRR_ARES
     730:     if(thrdd->rr.channel) {
     731:       struct Curl_https_rrinfo *lhrr = NULL;
     732:       if(thrdd->rr.hinfo.complete) {
     733:         lhrr = Curl_httpsrr_dup_move(&thrdd->rr.hinfo);
     734:         if(!lhrr) {
     735:           result = CURLE_OUT_OF_MEMORY;
     736:           goto out;
     737:         }
     738:       }
     739:       Curl_httpsrr_trace(data, lhrr);
     740:       Curl_dns_entry_set_https_rr(dns, lhrr);
     741:     }
     742: #endif
     743:   }
     744: 
     745:   if(dns) {
     746:     *pdns = dns;
     747:     dns = NULL;
     748:   }
     749: #ifdef CURLVERBOSE
     750:   Curl_thrdq_trace(data->multi->resolv_thrdq, data);
     751: #endif
     752: 
     753: out:
     754:   Curl_dns_entry_unlink(data, &dns);
     755:   Curl_async_thrdd_shutdown(data, async);
     756:   if(!result && !*pdns)
     757:     result = Curl_async_failed(data, async, NULL);
     758:   if(result &&
     759:      (result != CURLE_COULDNT_RESOLVE_HOST) &&
     760:      (result != CURLE_COULDNT_RESOLVE_PROXY)) {
     761:     CURL_TRC_DNS(data, "Error %d resolving %s:%d",
     762:                  result, async->hostname, async->port);
     763:   }
     764:   return result;
     765: }

