     874: {
     875:   CURLcode result = CURLE_OK;
     876:   enum dupstring i;
     877:   enum dupblob j;
     878: 
     879:   /* Copy src->set into dst->set first, then deal with the strings
     880:      afterwards */
     881:   dst->set = src->set;
     882: #if !defined(CURL_DISABLE_MIME) || !defined(CURL_DISABLE_FORM_API)
     883:   dst->set.mimepostp = NULL;
     884: #endif
