     926:     Curl_mime_initpart(dst->set.mimepostp);
     927:     result = Curl_mime_duppart(dst, dst->set.mimepostp, src->set.mimepostp);
     928:     if(result)
     929:       return result;
     930:   }
     931: #endif
     932: 
     933:   if(src->set.resolve)
     934:     dst->state.resolve = dst->set.resolve;
     935: 
     936:   return result;
     937: }

