    1542:       goto out;
    1543:     }
    1544: 
    1545:     /* after it was parsed, get the generated normalized version */
    1546:     uc = curl_url_get(uh, CURLUPART_URL, &newurl, CURLU_GET_EMPTY);
    1547:     if(uc) {
    1548:       result = Curl_uc_to_curlcode(uc);
    1549:       goto out;
    1550:     }
    1551:     Curl_bufref_set(&data->state.url, newurl, 0, curl_free);
    1552:   }
