    1558:   /* `uh` is now as the connection should use it, probably. */
    1559:   result = Curl_peer_from_url(uh, data, port_override, scope_id,
    1560:                               &data->state.up, &conn->origin);
    1561:   if(result)
    1562:     goto out;
    1563: 
    1564:   result = hsts_upgrade(data, conn, uh, port_override, scope_id);
    1565:   if(result)
    1566:     goto out;
    1567: 
    1568:   /* now that the origin is fixed, check and set the connection scheme */
    1569:   result = url_set_conn_scheme(data, conn, conn->origin->scheme);
    1570:   if(result)
    1571:     goto out;
    1572: 
    1573:   /* When the transfers initial_origin is not set, this is the initial
