    1582: 
    1583:   uc = curl_url_get(uh, CURLUPART_OPTIONS, &data->state.up.options,
    1584:                     CURLU_URLDECODE);
    1585:   if(!uc) {
    1586:     conn->options = curlx_strdup(data->state.up.options);
    1587:     if(!conn->options) {
    1588:       result = CURLE_OUT_OF_MEMORY;
    1589:       goto out;
    1590:     }
    1591:   }
    1592:   else if(uc != CURLUE_NO_OPTIONS) {
    1593:     result = Curl_uc_to_curlcode(uc);
    1594:     goto out;
    1595:   }
    1596: 
    1597:   uc = curl_url_get(uh, CURLUPART_PATH, &data->state.up.path, CURLU_URLENCODE);
    1598:   if(uc) {
    1599:     result = Curl_uc_to_curlcode(uc);
    1600:     goto out;
    1601:   }
    1602: 
    1603:   uc = curl_url_get(uh, CURLUPART_QUERY, &data->state.up.query,
    1604:                     CURLU_GET_EMPTY);
    1605:   if(uc && (uc != CURLUE_NO_QUERY)) {
    1606:     result = CURLE_OUT_OF_MEMORY;
    1607:     goto out;
    1608:   }
    1609: 
    1610: #ifdef USE_IPV6
    1611:   /* Fill in the conn parts that do not use authority, yet. */
    1612:   conn->scope_id = conn->origin->scopeid;
    1613: #endif
