     687: {
     688:   struct async_thrdd_ctx *thrdd = &async->thrdd;
     689:   struct Curl_dns_entry *dns = NULL;
     690:   CURLcode result = CURLE_OK;
     691: 
     692:   DEBUGASSERT(pdns);
     693:   *pdns = NULL;
     694:   if(!async->queries_ongoing && !async->done) {
     695:     DEBUGASSERT(0);
     696:     return CURLE_FAILED_INIT;
     697:   }
     698: 
     699: #ifdef USE_HTTPSRR_ARES
     700:   /* best effort, ignore errors */
